import { ExternalTokenizer } from '@lezer/lr';

import { characterCodes } from '../character-codes.js';
import { SearchOperator } from '../parser.terms.js';

const {
  ASTERISK,
  CLOSING_BRACKET,
  DOUBLEQUOTE,
  EOF,
  OPENING_BRACKET,
  SPACE,
  TILDE,
} = characterCodes;

// Valid input before a search operator. Every other input will result in the
// token not being accepted.
const validBeforeSearchOperator = [
  OPENING_BRACKET,
  CLOSING_BRACKET,
  DOUBLEQUOTE,
  SPACE,
  EOF,
];

/** @internal */
export const searchOperatorTokenizer = new ExternalTokenizer(
  (inputStream, stack) => {
    // No asterisk, definitely not a position operator.
    if (inputStream.next !== ASTERISK) {
      return;
    }

    const previousToken = stack.context.lastToken;

    // If the previous character is not a space or the start of the filter, we don't want
    // to detect a search operator, but instead a normal position operator.
    const previousChar = inputStream.peek(-1);
    if (
      previousToken !== 'expression' &&
      previousToken !== null &&
      !validBeforeSearchOperator.includes(previousChar)
    ) {
      return;
    }

    // If the asterisk is followed by a space, it may still be a valid search operator.
    // Advance the stream and continue checking.
    if (inputStream.peek(1) === SPACE) {
      inputStream.advance();
    }

    // Advance input stream by 1 and store the character code of the next character.
    const nextChar = inputStream.advance();
    // If it's not a tilde, return. Else, advance once more to include the tilde in the accepted
    // token and accept.
    if (nextChar !== TILDE) {
      return;
    }

    inputStream.advance();
    inputStream.acceptToken(SearchOperator);
  },
);
